parameters.jsCode:
const stdout = $input.first().json.stdout?.trim();
if (!stdout) return [];

const filePath = stdout;
const parts = filePath.split('/');
const filename = parts[parts.length - 1];
let category = parts[parts.length - 2];

// If in the '會議' (Meeting) subfolder, prepend '會議_' to category
if (parts.includes('會議') && category !== '會議') {
  category = `會議_${category}`;
}

console.log(`Found file to process: ${category}/${filename}`);
return [{ json: { body: { category, filename }, filePath } }];

const result = $input.first().json;
const stdout = result.stdout?.trim() || '';
const exitCode = result.exitCode;
if (exitCode !== 0 || stdout.startsWith('ERROR') || stdout === 'BUSY') {
  console.log('Stop reason:', stdout || `exitCode=${exitCode}`);
  return [];
}
console.log('Audio file copied successfully, continuing workflow');
return $input.all();

const items = $input.all();
const wfStatic = $getWorkflowStaticData('global');
wfStatic['current_run'] = { totalChunks: items.length, completedCount: 0, results: [] };
console.log(`Initialization complete, total ${items.length} chunks`);
return items.map((item, index) => ({
  json: { chunkIndex: index, totalChunks: items.length },
  binary: { data: Object.values(item.binary)[0] }
}));

const items = $input.all();
const wfStatic = $getWorkflowStaticData('global');
if (!wfStatic['current_run']) {
  wfStatic['current_run'] = { totalChunks: 0, completedCount: 0, results: [] };
}
if (items[0]?.json?.error) {
  wfStatic['current_run'].completedCount += 1;
  return [{ json: { completed: wfStatic['current_run'].completedCount, total: wfStatic['current_run'].totalChunks } }];
}
let text = items[0]?.json?.text || '';
const lines = text.split(/[，。？！\n]/);
const seen = {};
let cleanLines = [];
for (const line of lines) {
  const trimmed = line.trim();
  if (!trimmed) continue;
  seen[trimmed] = (seen[trimmed] || 0) + 1;
  if (seen[trimmed] <= 3) cleanLines.push(trimmed);
}
text = cleanLines.join('，');
wfStatic['current_run'].results.push(text);
wfStatic['current_run'].completedCount += 1;
const completed = wfStatic['current_run'].completedCount;
const total = wfStatic['current_run'].totalChunks;
console.log(`Completed ${completed} / ${total} chunks`);
return [{ json: { completed, total } }];

const wfStatic = $getWorkflowStaticData('global');
const container = wfStatic['current_run'] || { results: [] };
function cleanHallucinations(text) {
  if (!text) return '';
  let cleaned = text.replace(/(.{2,10}?)\1{3,}/g, '$1');
  cleaned = cleaned.replace(/(.)\1{5,}/g, '$1');
  return cleaned.trim();
}
const fullText = container.results
  .filter(t => t && t.trim().length > 0)
  .map(t => cleanHallucinations(t))
  .join('\n\n');
console.log(`Transcript combined, total ${container.results.length} segments`);
return [{ json: { fullText } }];

